+/// Find the first CRLF line terminator at or after `start`, returning the
+/// index of the `\r` byte.
+fn find_crlf(buf: &[u8], start: usize) -> Option<usize> {
+    if start >= buf.len() {
+        return None;
+    }
+    let mut i = start;
+    while i + 1 < buf.len() {
+        if buf[i] == b'\r' && buf[i + 1] == b'\n' {
+            return Some(i);
+        }
+        i += 1;
+    }
+    None
 }

